export const getStyleUI = (lang) => styleUITranslations[lang] || styleUITranslations.EN;
// Получение названия категории на нужном языке
export const getCategoryName = (category, lang) => {
    const ui = getStyleUI(lang);
    const names = {
        casual: ui.casualTitle,
        work: ui.workTitle,
        date: ui.dateTitle,
        social: ui.socialTitle,
        event: ui.eventTitle,
        custom: ui.customTitle
    };
    return names[category];
};
// Получение описания категории на нужном языке
export const getCategoryDescription = (category, lang) => {
    const ui = getStyleUI(lang);
    const descriptions = {
        casual: ui.casualDesc,
        work: ui.workDesc,
        date: ui.dateDesc,
        social: ui.socialDesc,
        event: ui.eventDesc,
        custom: ui.customDesc
    };
    return descriptions[category];
};
